#!/usr/bin/env node

import chalk from 'chalk';
import { program } from 'commander';
import fs from 'fs-extra';
import path, { dirname } from 'path';
import { fileURLToPath } from 'url';
import add from '../lib/commands/add.js';
import init from '../lib/commands/init.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// Read package.json
const pkg = JSON.parse(fs.readFileSync(path.resolve(__dirname, '../package.json'), 'utf8'));

// Setup program
program
  .name('transtrack-ui')
  .description('CLI untuk menginstal component UI Nuxt 3 dengan Tailwind CSS')
  .version(pkg.version);

// Init command
program
  .command('init')
  .description('Inisialisasi konfigurasi untuk proyek Nuxt Anda')
  .action(init);

// Add command
program
  .command('add [components...]')
  .description('Tambahkan component UI atau icon ke proyek Anda')
  .option('-d, --directory <directory>', 'Direktori instalasi component', 'components/general')
  .action(add);

// Show help if no args
if (process.argv.length < 3) {
  console.log(chalk.bold('\n Transtrack UI'));
  console.log(`
${chalk.cyan('Penggunaan:')}
  transtrack init
  transtrack add Button Chip
  transtrack add IconName

${chalk.cyan('Perintah:')}
  init                Inisialisasi konfigurasi
  add [components]    Tambahkan component atau icon ke proyek Anda
  `);
}

program.parse(process.argv);